"""Data models."""

class User:
    def __init__(self, username, email, role="viewer"):
        self.username = username
        self.email = email
        self.role = role
        self.active = True

    def to_dict(self):
        return {
            "username": self.username,
            "email": self.email,
            "role": self.role,
            "active": self.active,
