    def __init__(self, name, price, category, stock=0):
        self.name = name
        self.price = price
        self.category = category
        self.stock = stock

    def to_dict(self):
        return {
            "name": self.name,
            "price": self.price,
            "category": self.category,
            "stock": self.stock,
        }

